 1	import React, { FC, useMemo } from 'react';
 2	import { ReactNode } from 'react';
 3	
 4	import SubTitleChartLabel from '@kubevirt-utils/components/Charts/ChartLabels/SubTitleChartLabel';
 5	import TitleChartLabel from '@kubevirt-utils/components/Charts/ChartLabels/TitleChartLabel';
 6	import LoadingEmptyState from '@kubevirt-utils/components/LoadingEmptyState/LoadingEmptyState';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { ChartDonut } from '@patternfly/react-charts';
 9	import { CardBody } from '@patternfly/react-core';
10	
11	import useVMsPerResource from './hooks/useVMsPerResource';
12	import {
13	  getChartData,
14	  getInstanceTypeSeriesLabel,
15	  getResourceLegendItems,
16	  getResourcesToVMCountMap,
17	  vmsPerResourceCount,
18	} from './utils/utils';
19	import EmptyStateNoVMs from './EmptyStateNoVMs';
20	import RunningVMsChartLegend from './RunningVMsChartLegend';
21	
22	import './VMsPerResourceCard.scss';
23	type VMsPerResourceChartProps = {
24	  type: string;
25	};
26	const VMsPerResourceChart: FC<VMsPerResourceChartProps> = ({ type }) => {
27	  const { t } = useKubevirtTranslation();
28	  const { loaded, vms } = useVMsPerResource();
29	
30	  const resourceToVMCountMap = useMemo(
31	    () => getResourcesToVMCountMap(loaded, vms, type),
32	    [loaded, vms, type],
33	  );
34	
35	  const chartData = getChartData(resourceToVMCountMap);
36	  const legendItems = getResourceLegendItems(resourceToVMCountMap);
37	  const vmsPerResourcesCount = vmsPerResourceCount(resourceToVMCountMap);
38	
39	  const RunningVMsChart = (
40	    <div>
41	      <ChartDonut
42	        padding={{
43	          bottom: 20,
44	          left: 20,
45	          right: 20,
46	          top: 20,
47	        }}
48	        style={{
49	          labels: {
50	            fontSize: 5,
51	          },
52	        }}
53	        ariaDesc={t('VirtualMachines per resource')}
54	        ariaTitle={t('VirtualMachines per resource')}
55	        data={chartData}
56	        height={150}
57	        labels={({ datum }) => `${getInstanceTypeSeriesLabel(datum.x)}: ${datum.y}%`}
58	        subTitle={t('VMs')}
59	        subTitleComponent={<SubTitleChartLabel />}
60	        title={vmsPerResourcesCount?.toString()}
61	        titleComponent={<TitleChartLabel />}
62	        width={300}
63	      />
64	    </div>
65	  );
66	
67	  let body: ReactNode = null;
68	  if (!loaded) {
69	    body = <LoadingEmptyState />;
70	  } else if (!vmsPerResourcesCount) {
71	    body = <EmptyStateNoVMs />;
72	  } else {
73	    body = (
74	      <>
75	        {RunningVMsChart}
76	        <RunningVMsChartLegend legendItems={legendItems} />
77	      </>
78	    );
79	  }
80	
81	  return <CardBody>{body}</CardBody>;
82	};
83	
84	export default VMsPerResourceChart;

